use std::collections::BTreeMap;
use std::env;
use std::fs;
use std::path::PathBuf;

fn main() {
  let manifest_dir =
    PathBuf::from(env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR not set"));

  let input = manifest_dir.join("unicode").join("CaseFolding.txt");
  println!("cargo:rerun-if-changed={}", input.display());

  let out_dir = PathBuf::from(env::var("OUT_DIR").expect("OUT_DIR not set"));
  let out_file = out_dir.join("regexp_case_folding_table.rs");

  let raw = fs::read_to_string(&input).expect("read unicode/CaseFolding.txt");
  let version_line = raw.lines().next().unwrap_or("").trim();

  // Mapping for RegExp case folding:
  // - Canonicalize (ECMA-262): "simple or common case folding mapping"
  // - scf (ECMA-262): Simple Case Folding mapping used by v-mode set canonicalization
  //
  // Unicode CaseFolding.txt status legend:
  // - C: common case folding mapping
  // - S: simple case folding mapping
  // - F: full case folding mapping (may expand to multiple code points)
  // - T: Turkic special-casing mapping
  //
  // For ECMAScript RegExp case folding, we include C + S and ignore F + T.
  let mut map: BTreeMap<u32, u32> = BTreeMap::new();

  for (idx, raw_line) in raw.lines().enumerate() {
    let line_no = idx + 1;
    let line = raw_line.split('#').next().unwrap_or("").trim();
    if line.is_empty() {
      continue;
    }

    let mut fields = line.split(';').map(|s| s.trim());
    let from_hex = fields
      .next()
      .unwrap_or_else(|| panic!("CaseFolding.txt:{line_no}: missing code point"));
    let status = fields
      .next()
      .unwrap_or_else(|| panic!("CaseFolding.txt:{line_no}: missing status"));
    let mapping_raw = fields
      .next()
      .unwrap_or_else(|| panic!("CaseFolding.txt:{line_no}: missing mapping"));

    let include = match status {
      "C" | "S" => true,
      "F" | "T" => false,
      other => panic!("CaseFolding.txt:{line_no}: unexpected status {other:?}"),
    };
    if !include {
      continue;
    }

    let from = u32::from_str_radix(from_hex, 16).unwrap_or_else(|_| {
      panic!("CaseFolding.txt:{line_no}: invalid code point {from_hex:?}")
    });
    if from > 0x10FFFF {
      panic!("CaseFolding.txt:{line_no}: code point out of range: 0x{from:06X}");
    }

    let mut mapping_parts = mapping_raw.split_whitespace();
    let to_hex = mapping_parts.next().unwrap_or_else(|| {
      panic!("CaseFolding.txt:{line_no}: missing mapping code point")
    });
    let to = u32::from_str_radix(to_hex, 16)
      .unwrap_or_else(|_| panic!("CaseFolding.txt:{line_no}: invalid mapping {to_hex:?}"));
    if to > 0x10FFFF {
      panic!("CaseFolding.txt:{line_no}: mapping out of range: 0x{to:06X}");
    }

    // For the mappings we include, we must assert that they are single code point -> single code
    // point. This protects against accidentally treating full case folding as simple folding by
    // taking only the first code point.
    if mapping_parts.next().is_some() {
      panic!(
        "CaseFolding.txt:{line_no}: expected single code point mapping for status {status:?}, got {mapping_raw:?}"
      );
    }

    if let Some(prev) = map.insert(from, to) {
      if prev != to {
        panic!(
          "CaseFolding.txt:{line_no}: duplicate mapping for 0x{from:04X}: 0x{prev:04X} vs 0x{to:04X}"
        );
      }
    }
  }

  let mut out = String::new();
  out.push_str("// @generated by vm-js/build.rs - do not edit.\n");
  if version_line.starts_with('#') {
    out.push_str(&format!("// Source: unicode/CaseFolding.txt ({version_line}).\n"));
  } else {
    out.push_str("// Source: unicode/CaseFolding.txt.\n");
  }
  out.push_str("pub(crate) const REGEXP_CASE_FOLDING: &[(u32, u32)] = &[\n");
  for (from, to) in map {
    out.push_str(&format!("  (0x{from:04X}, 0x{to:04X}),\n"));
  }
  out.push_str("];\n");

  fs::write(&out_file, out).expect("write regexp_case_folding_table.rs");
}

